function data = mdp_TongArea(data, varargin)%MDP_TONGAREA - MVIEW dataproc that computes the area between the tongue sensors and the palate%%	varargin{1} - tongue sensor list defaults to {'TR','TB','TT}%% appends AREA signal as DATA(end+1)%% AREA is computed as the convex hull determined by the tongue sensors and the palate% N.B. palate trace must be loaded and available; sensors must be specified in back-to-front order%% Example 1 (DATA includes TR,TB,TT trajectories):% mview(...,'DPROC','mdp_TongArea, ...)%% Example 2 (explicit names for TD and TT trajectories):% mview(...,'DPROC',{'mdp_LipAperture',{'mdp_TongArea',{'TD','TT'}}}, ...)% mkt 03/17 modif length(varargin) < 2, error('missing palate trace'); end;pal = varargin{end}; pal = pal(1);pal = pal{1}(:,[1 3]);k = [0 ; cumsum(sqrt(sum(diff(pal).^2,2)))];pal = interp1(k,pal,linspace(0,k(end),50));		% resample to 50 equally spaced pointspal = flipud(pal);								% front to back orderif length(varargin) > 2,	% last arg is {pal,phar,labs}	traj = upper(varargin(1:end-1));else,	traj = {'TR','TB','TT'};end;names = upper({data.NAME});nSamps = size(data(end).SIGNAL(:,1),1);x = NaN(nSamps,length(traj));y = x;for ti = 1 : length(traj),	k = find(strcmp(traj{ti}, names));	if isempty(k), error('can''t find %s in data', traj{ti}); end;	x(:,ti) = data(k).SIGNAL(:,1);	y(:,ti) = data(k).SIGNAL(:,3);end;x = [x , ones(nSamps,1)*pal(:,1)']';y = [y , ones(nSamps,1)*pal(:,2)']';data(end+1) = data(end);data(end).NAME = 'AREA';data(end).SIGNAL = polyarea(x,y)';minS = min(data(end).SIGNAL);maxS = max(data(end).SIGNAL);spread = maxS - minS;data(end).SPREAD = [minS-spread*.1 maxS+spread*.1];	%paddata(end).NCOMPS = 1;